endpoint.response:

{
  success: true,
  message: string,
  data: {
    items: Array<{
      id: number,                 // activity_log.id
      logged_at: string,          // ISO 8601 (created_at)
      event: 'created'|'updated'|'deleted'|'restored',
      module: string,             // alias morph subject_type: 'user'|'personal_data'|'contact'|'address'
      subject_id: number,
      causer: { id: number|null, name: string|null },
      changes: Array<{ field: string, old_value: unknown|null, new_value: unknown|null }>
    }>,
    next_cursor: string|null       // null = ultima pagina
  }
}
